import java.math.BigDecimal;
import java.util.Collection;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

public class BerekenSocialeBijdragenDmfa extends BerekenSocialeBijdragenDmfappl {
    public static final int SCALE = 2;

    private static final Set<MoneyKey> BIJDRAGEN = ImmutableSet.of(
            RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_FONDS_SLUITING_ONDERNEMING_KEY,//810
            RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_FSO_NIET_COMMERCIELE_WERKGEVERS_KEY,//811
            RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_VERBREKINGSVERGOEDINGEN_SLUITINGSFONDS_KEY,//812
            RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_FONDSEN_BESTAANSZEKERHEID_ARBEIDERS_KEY,//820
            RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_FONDSEN_BESTAANSZEKERHEID_BEDIENDEN_KEY,//830
            RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_SECTORAAL_PENSIOENFONDS_ARBEIDERS_KEY,//825
            RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_SECTORAAL_PENSIOENFONDS_BEDIENDEN_KEY,//835
            RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_WERKGELEGENHEID_EN_VORMING_KEY,//852
            RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_TIJDELIJKE_WERKLOOSHEID_KEY,//859
            RekenRszKey.BIJDRAGE_WINST_PREMIE_KEY,
            RekenPatronaalRszKey.PATRONALE_BASISBIJDRAGE_RSZ_ZIV_KEY,
            RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_VAKREG_PRIVESECTOR_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJZONDERE_BIJDRAGE_ARBEIDSONGEVALLEN,
            RekenPatronaalRszKey.PATRONALE_BIJZONDERE_BIJDRAGE_ASBESTFONDS
    );

    private static final Set<Sleutel<?>> BIJDRAGE_RSZ_SLEUTEL = ImmutableSet.of(
            SleutelWerkgeversCategorie.INSTANCE,
            SleutelWerknemersKengetal.INSTANCE,
            SleutelPensioenStelsel.INSTANCE,
            SleutelVerminderingsCode.INSTANCE,
            SleutelVrijstellingTweedePensioenpijler.INSTANCE,
            SleutelStatuutDmfappl.INSTANCE,
            SleutelTypeLeerling.INSTANCE);

    private static final Set<Sleutel<?>> BASIS_RSZ_SLEUTEL = ImmutableSet.of(
            SleutelWerkgeversCategorie.INSTANCE,
            SleutelWerknemersKengetal.INSTANCE,
            SleutelPensioenStelsel.INSTANCE,
            SleutelStatuutDmfappl.INSTANCE,
            SleutelVrijstellingTweedePensioenpijler.INSTANCE,
            SleutelVerminderingsCode.INSTANCE);

    public BerekenSocialeBijdragenDmfa(ConstantManager constantManager, NlpGlobalService globalService) {
        super(constantManager, globalService);
    }

    @Override
    public Set<Sleutel<?>> getBijdrageRszSleutel() {
        return BIJDRAGE_RSZ_SLEUTEL;
    }

    @Override
    public Set<Sleutel<?>> getBasisRszSleutel() {
        return BASIS_RSZ_SLEUTEL;
    }

    @Override
    public void berekenSocialeBijdrageMonitoren(RekenContext opdrachtContext, Opdracht opdracht) {
        // Er mogen geen bijdragen meer gerekend worden voor monitoren
    }

    @Override
    protected BasisRszVerdelerOptions createBasisRszVerdelerOptions(
            RekenTijd rekenTijd, SleutelGegevens aggregaat, boolean bestuurBerekentTweedePensioenPijler, LocalDate gegevensDatum, CategorieKengetal categorieKengetal) {
        BasisRszVerdelerOptions options =
                super.createBasisRszVerdelerOptions(rekenTijd, aggregaat, bestuurBerekentTweedePensioenPijler, gegevensDatum, categorieKengetal);
        boolean isSectoraalPensioenfondsArbeidersRekenen = BijdrageSectoraalPensioenfondsArbeiders.isSectoraalPensioenfondsArbeidersRekenen(constantManager, rekenTijd);
        options.setSectoraalPensioenfondsArbeiders(isSectoraalPensioenfondsArbeidersRekenen);

        return options;
    }

    @Override
    protected BasisRszVerdeler getBasisRszVerdelerZonderLoonElement(
            Hoedanigheid hoedanigheid, RegulManager regulManager, LocalDate gegevensDatum,
            Gsd typeGsd, CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel, BasisRszVerdelerOptions options) {
        return new BasisRszVerdelerDmfa(
                getDmfapplBasisBijdrageService(),
                getApkPrincipeService(),
                regulManager,
                hoedanigheid,
                typeGsd,
                categorieKengetalStatuutPensioenstelsel,
                gegevensDatum,
                options,
                new IsPool2TerDmfa(constantManager),
                new AsbestfondsManager(constantManager));
    }

    @Override
    protected void opsplitsenPatronaleBijdrage2dePensioenpijler(RekenContext opdrachtContext, List<SleutelGegevens> aggregaten) {
        for (SleutelGegevens aggregaat : aggregaten) {
            LoonElementManager manager = opdrachtContext.getLoonElementManager();
            Collection<LoonElement> opperElementen = aggregaat.getOpperElementen(manager);
            for (LoonElement element : opperElementen) {
                opsplitsenPatronaleBijdrage2dePensioenpijler(element);
            }
        }
    }

    protected void opsplitsenPatronaleBijdrage2dePensioenpijler(LoonElement element) {
        Money totaalPens2 = element.getPropertyMoney(RekenPatronaalRszKey.PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY);

        Money pens2 = totaalPens2.divide(new BigDecimal("1.09")).round(SCALE);
        element.putProperty(RekenPatronaalRszKey.PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY, pens2);

        Money bijzonderPens2 = totaalPens2.subtract(pens2);
        element.putProperty(RekenPatronaalRszKey.BIJZONDERE_PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY, bijzonderPens2);
    }

    @Override
    public void berekenSocialeBijdragenMandataris(RekenContext opdrachtContext, Opdracht opdracht) {
        berekenSocialeBijdragenRszppoPlichtig(opdrachtContext, opdracht);
    }

    @Override
    public Set<MoneyKey> getBijdragen() {
        Set<MoneyKey> bijdragen = new HashSet<>();
        bijdragen.addAll(super.getBijdragen());
        bijdragen.addAll(BIJDRAGEN);
        return ImmutableSet.copyOf(bijdragen);
    }
}
